import{_ as e,c as o,o as r,a1 as n}from"./chunks/framework.DDNAyvCW.js";const s="/assets/term.DbmQQMzo.png",h=JSON.parse('{"title":"Terminal Settings","description":"","frontmatter":{},"headers":[],"relativePath":"docs/settings/terminal/index.md","filePath":"docs/settings/terminal/index.md"}'),a={name:"docs/settings/terminal/index.md"};function i(d,t,l,c,g,u){return r(),o("div",null,t[0]||(t[0]=[n('<h1 id="terminal-settings" tabindex="-1">Terminal Settings <a class="header-anchor" href="#terminal-settings" aria-label="Permalink to &quot;Terminal Settings&quot;">​</a></h1><p>Configure terminal emulation, fonts, cursor style, scrollback, and input behavior.</p><p><img src="'+s+'" alt=""></p><h2 id="settings-overview" tabindex="-1">Settings Overview <a class="header-anchor" href="#settings-overview" aria-label="Permalink to &quot;Settings Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><strong>Terminal Type</strong></td><td>xterm</td><td>Terminal emulator type. Options include xterm, vt100, and others.</td></tr><tr><td><strong>Font</strong></td><td>Monaco / Menlo</td><td>Monospace font used in the terminal.</td></tr><tr><td><strong>Font Size</strong></td><td>14 px</td><td>Font size for terminal text.</td></tr><tr><td><strong>Scrollback</strong></td><td>1000 lines</td><td>Number of lines kept in terminal history.</td></tr><tr><td><strong>Cursor Style</strong></td><td>Block</td><td>Cursor shape: Block, Underline, or Bar.</td></tr><tr><td><strong>Trackpad Zoom</strong></td><td>Disabled</td><td>Enable pinch-to-zoom gestures to resize terminal font.</td></tr><tr><td><strong>SSH Agents</strong></td><td>--</td><td>SSH key agent and forwarding configuration.</td></tr><tr><td><strong>Proxy</strong></td><td>--</td><td>Network proxy for terminal connections.</td></tr><tr><td><strong>Mouse Middle Button</strong></td><td>Paste</td><td>Action triggered by middle-click in the terminal.</td></tr><tr><td><strong>Mouse Right Button</strong></td><td>Context Menu</td><td>Action triggered by right-click in the terminal.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Font Recommendation</p><p>Use a monospace font (e.g., Monaco, Menlo, Consolas, JetBrains Mono) to keep code and command output aligned. A font size of 12--14 px works well on most displays.</p></div><div class="warning custom-block"><p class="custom-block-title">Scrollback Memory Usage</p><p>High scrollback values consume more memory. For most workflows, 1000--5000 lines is sufficient. If you regularly inspect large log output, consider piping to a file or using terminal search (<code>Cmd + F</code> / <code>Ctrl + F</code>) instead.</p></div><h2 id="ssh-agents" tabindex="-1">SSH Agents <a class="header-anchor" href="#ssh-agents" aria-label="Permalink to &quot;SSH Agents&quot;">​</a></h2><p>SSH Agent settings let you manage keys and enable agent forwarding for jump-host scenarios.</p><ul><li><strong>SSH Agent Forwarding</strong> -- forwards your local SSH agent through remote connections, so you can authenticate to a second host without copying keys.</li><li><strong>Key Management</strong> -- add, remove, or reorder SSH keys used for connections.</li><li><strong>Auto Authentication</strong> -- after configuration, Chaterm uses the appropriate key automatically when connecting.</li></ul><h2 id="proxy-configuration" tabindex="-1">Proxy Configuration <a class="header-anchor" href="#proxy-configuration" aria-label="Permalink to &quot;Proxy Configuration&quot;">​</a></h2><p>Route terminal connections through a network proxy.</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Protocol</strong></td><td>HTTP, HTTPS, or SOCKS5.</td></tr><tr><td><strong>Address</strong></td><td>Hostname or IP of the proxy server.</td></tr><tr><td><strong>Port</strong></td><td>Port number of the proxy server.</td></tr><tr><td><strong>Username / Password</strong></td><td>Credentials, if the proxy requires authentication.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Proxy settings apply to all terminal connections. Incorrect configuration may prevent connections from succeeding. Verify the proxy address and port before saving.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/docs/settings/general/">General Settings</a> -- theme, language, layout, and editor options</li><li><a href="/docs/settings/shortcuts/">Shortcut Settings</a> -- keyboard shortcuts for terminal operations and more</li></ul>',16)]))}const p=e(a,[["render",i]]);export{h as __pageData,p as default};
